#!/bin/bash
set -e
# Deploy App.tsx — new forensics Evidence tab
echo '' | base64 -d > src/App.tsx
# Patch server.ts: suppress git rev-parse stderr (already on disk, just patch)
sed -i "s/{ cwd: WORKSPACE_DIR, encoding: 'utf8' }).trim().slice(0, 7);/{ cwd: WORKSPACE_DIR, encoding: 'utf8', stdio: ['ignore','pipe','ignore'] }).trim().slice(0, 7);/g" server.ts
# Patch dashboard.ts: add SIGINT/SIGTERM cleanExit if not already present
grep -q 'cleanExit' dashboard.ts || sed -i "s/screen.key(\['q', 'C-c'\], () => { screen.destroy(); process.exit(0); });/const cleanExit = () => { try { screen.destroy(); } catch { } process.exit(0); };\n  screen.key(['q', 'C-c'], cleanExit);\n  process.on('SIGINT',  cleanExit);\n  process.on('SIGTERM', cleanExit);/" dashboard.ts
# Verify
grep -c 'fetchForensics' src/App.tsx && echo 'App.tsx forensics OK'
grep -q 'cleanExit' dashboard.ts && echo 'dashboard Ctrl-C OK' || echo 'WARNING: cleanExit not found'
grep -q 'ignore.*pipe.*ignore' server.ts && echo 'server git stderr OK' || echo 'WARNING: stdio fix not found'
# Commit
git add src/App.tsx server.ts dashboard.ts
git commit -m 'fix: App.tsx /api/forensics Evidence tab; healthPing/Dns/Route breakdown; Ctrl-C terminal restore; git stderr suppressed'
git push origin master